package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.File;
import java.io.IOException;
import java.nio.charset.StandardCharsets;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @TempDir
    File tempDir;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrintWithValidFile() throws IOException {
        File file = new File(tempDir, "test.csv");
        CSVPrinter printer = csvFormat.print(file, StandardCharsets.UTF_8);
        assertNotNull(printer);
        printer.close();
        assertTrue(file.exists());
        assertTrue(file.length() >= 0);
    }

    @Test
    void testPrintWithNullCharset() {
        File file = new File(tempDir, "test.csv");
        assertThrows(NullPointerException.class, () -> csvFormat.print(file, null));
    }

    @Test
    void testPrintWithNonWritableFile() {
        File file = new File(tempDir, "readonly.csv");
        try {
            boolean created = file.createNewFile();
            assertTrue(created || file.exists());
            boolean madeReadOnly = file.setReadOnly();
            assertTrue(madeReadOnly || !file.canWrite());
        } catch (IOException e) {
            fail("Setup failed: " + e.getMessage());
        }
        assertThrows(IOException.class, () -> csvFormat.print(file, StandardCharsets.UTF_8));
    }
}
